field.text:
checkpoints({
  description: "Analyze employee dataset",
  tasks: [
    { id: "load", instructions: "Load the employee dataset", outputSchema: { count: { type: "number" } } },
    { id: "employees_per_department", instructions: "Count employees per department", outputSchema: { counts: { type: "object" } } },
    { id: "average_salary_by_department", instructions: "Calculate average salary by department", outputSchema: { averages: { type: "object" } } },
    { id: "top_3_highest_paid", instructions: "Find top 3 highest paid employees", outputSchema: { employees: { type: "array" } } },
    { id: "typescript_employees", instructions: "Find employees who know TypeScript", outputSchema: { employees: { type: "array" } } }
  ]
})

var employees = await getEmployees()
await stop(employees)

checkpoint("load", { count: employees.length })

var employeesPerDept = countByField(employees, "department")
await stop(employeesPerDept)

checkpoint("employees_per_department", { counts: employeesPerDept })

var avgSalaryByDept = {}
for (var dept in employeesPerDept) {
  var deptEmployees = filterBy(employees, "department", dept)
  avgSalaryByDept[dept] = average(deptEmployees, "salary")
}
await stop(avgSalaryByDept)

checkpoint("average_salary_by_department", { averages: avgSalaryByDept })

var top3HighestPaid = topN(employees, "salary", 3)
await stop(top3HighestPaid)

checkpoint("top_3_highest_paid", { employees: top3HighestPaid })

var typescriptEmployees = findSkill(employees, "TypeScript")
await stop(typescriptEmployees)

checkpoints({
  description: "Analyze employee dataset",
  tasks: [
    { id: "load", instructions: "Load the employee dataset", outputSchema: { count: { type: "number" } } },
    { id: "employees_per_department", instructions: "Count employees per department", outputSchema: { counts: { type: "object" } } },
    { id: "average_salary_by_department", instructions: "Calculate average salary by department", outputSchema: { averages: { type: "object" } } },
    { id: "top_3_highest_paid", instructions: "Find top 3 highest paid employees", outputSchema: { employees: { type: "array" } } },
    { id: "typescript_employees", instructions: "Find employees who know TypeScript", outputSchema: { employees: { type: "array" } } }
  ]
})

var employees = await getEmployees()
await stop(employees)

checkpoint("load", { count: employees.length })

var employeesPerDept = countByField(employees, "department")
await stop(employeesPerDept)

checkpoint("employees_per_department", { counts: employeesPerDept })

var avgSalaryByDept = {}
for (var dept in employeesPerDept) {
  var deptEmployees = filterBy(employees, "department", dept)
  avgSalaryByDept[dept] = average(deptEmployees, "salary")
}
await stop(avgSalaryByDept)

checkpoint("average_salary_by_department", { averages: avgSalaryByDept })

var top3HighestPaid = topN(employees, "salary", 3)
await stop(top3HighestPaid)

checkpoint("top_3_highest_paid", { employees: top3HighestPaid })

var typescriptEmployees = findSkill(employees, "TypeScript")
await stop(typescriptEmployees)
